ExternalServiceRegistration.schema:
{
  "openapi": "3.0.0",
  "info": {
    "title": "Bot API Ollin Proteccion V2",
    "version": "1.0.0",
    "description": "API completa para cotización y emisión de seguros de auto para Agentforce"
  },
  "paths": {
    "/bot/catalog/years": {
      "get": {
        "operationId": "getYears",
        "responses": {
          "200": {
            "description": "Lista de años",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "items": { "type": "array", "items": { "type": "integer" } }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/bot/catalog/brands": {
      "get": {
        "operationId": "getBrands",
        "parameters": [
          { "name": "year", "in": "query", "required": true, "schema": { "type": "string" } }
        ],
        "responses": {
          "200": {
            "description": "Lista de marcas",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "items": {
                      "type": "array",
                      "items": {
                        "type": "object",
                        "properties": {
                          "id": { "type": "string" },
                          "name": { "type": "string" }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/bot/catalog/models": {
      "get": {
        "operationId": "getModels",
        "parameters": [
          { "name": "year", "in": "query", "required": true, "schema": { "type": "string" } },
          { "name": "brandId", "in": "query", "required": true, "schema": { "type": "string" } }
        ],
        "responses": {
          "200": {
            "description": "Lista de modelos",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "items": {
                      "type": "array",
                      "items": {
                        "type": "object",
                        "properties": {
                          "id": { "type": "string" },
                          "name": { "type": "string" }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/bot/catalog/versions": {
      "get": {
        "operationId": "getVersions",
        "parameters": [
          { "name": "year", "in": "query", "required": true, "schema": { "type": "string" } },
          { "name": "modelId", "in": "query", "required": true, "schema": { "type": "string" } }
        ],
        "responses": {
          "200": {
            "description": "Lista de versiones",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "items": {
                      "type": "array",
                      "items": {
                        "type": "object",
                        "properties": {
                          "id": { "type": "string" },
                          "name": { "type": "string" }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/bot/quotation": {
      "post": {
        "operationId": "createQuotation",
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "properties": {
                  "vehicleVersionId": { "type": "string" },
                  "coverage": { "type": "string", "enum": ["AMPLIA", "LIMITADA", "RC"] },
                  "insured": {
                    "type": "object",
                    "properties": {
                      "name": { "type": "string" },
                      "zipCode": { "type": "string" },
                      "birthDate": { "type": "string" },
                      "gender": { "type": "string", "enum": ["M", "F"] },
                      "phone": { "type": "string" }
                    }
                  }
                }
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Cotización generada",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "quotationId": { "type": "string" },
                    "expiresAt": { "type": "string" },
                    "results": {
                      "type": "array",
                      "items": {
                        "type": "object",
                        "properties": {
                          "insurer": { "type": "string" },
                          "packages": {
                            "type": "array",
                            "items": {
                              "type": "object",
                              "properties": {
                                "planId": { "type": "string" },
                                "planName": { "type": "string" },
                                "totalAmount": { "type": "number" }
                              }
                            }
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/bot/quotation/{quotationId}/select": {
      "post": {
        "operationId": "selectPlan",
        "parameters": [
          { "name": "quotationId", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "properties": {
                  "insurer": { "type": "string" }
                }
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Plan seleccionado y campos requeridos",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "requiredFields": {
                      "type": "array",
                      "items": {
                        "type": "object",
                        "properties": {
                          "field": { "type": "string" },
                          "type": { "type": "string" },
                          "required": { "type": "boolean" },
                          "description": { "type": "string" },
                          "options": {
                            "type": "array",
                            "items": {
                              "type": "object",
                              "properties": {
                                "value": { "type": "string" },
                                "label": { "type": "string" }
                              }
                            }
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/bot/quotation/{quotationId}/insured": {
      "post": {
        "operationId": "submitInsuredData",
        "parameters": [
          { "name": "quotationId", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "additionalProperties": true
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Póliza creada y link de pago",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "policyId": { "type": "string" },
                    "paymentUrl": { "type": "string" },
                    "status": { "type": "string" }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/bot/policy/{policyId}/payment-link": {
      "get": {
        "operationId": "getPaymentLink",
        "parameters": [
          { "name": "policyId", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "responses": {
          "200": {
            "description": "Enlace de pago",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "paymentUrl": { "type": "string" },
                    "amount": { "type": "number" },
                    "expiresAt": { "type": "string" }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/bot/policy/{policyId}": {
      "get": {
        "operationId": "getPolicyStatus",
        "parameters": [
          { "name": "policyId", "in": "path", "required": true, "schema": { "type": "string" } }
        ],
        "responses": {
          "200": {
            "description": "Estado de la póliza",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "status": { "type": "string" },
                    "policyNumber": { "type": "string" }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/bot/insurers": {
      "get": {
        "operationId": "getInsurers",
        "responses": {
          "200": {
            "description": "Lista de aseguradoras",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "items": { "type": "array", "items": { "type": "string" } }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/bot/coverages": {
      "get": {
        "operationId": "getCoverages",
        "responses": {
          "200": {
            "description": "Lista de coberturas",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "items": {
                      "type": "array",
                      "items": {
                        "type": "object",
                        "properties": {
                          "id": { "type": "string" },
                          "name": { "type": "string" }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/bot/installment-options": {
      "get": {
        "operationId": "getInstallmentOptions",
        "parameters": [
          { "name": "quotationId", "in": "query", "required": false, "schema": { "type": "string" } }
        ],
        "responses": {
          "200": {
            "description": "Opciones de pago",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "items": {
                      "type": "array",
                      "items": {
                        "type": "object",
                        "properties": {
                          "months": { "type": "integer" },
                          "label": { "type": "string" },
                          "amount": { "type": "number" }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}
